@@ -0,0 +1,47 @@
+{
+  "name": "ech_uses_bg_color",
+  "description": "ECH fills erased cells with current background color",
+  "initial_size": [
+    8,
+    3
+  ],
+  "input_bytes_hex": "414243441b5b34346d1b5b313b32481b5b3258",
+  "expected": {
+    "cursor": {
+      "row": 0,
+      "col": 1
+    },
+    "cells": [
+      {
+        "row": 0,
+        "col": 0,
+        "char": "A"
+      },
+      {
+        "row": 0,
+        "col": 1,
+        "char": " ",
+        "attrs": {
+          "bg_color": {
+            "named": 4
+          }
+        }
+      },
+      {
+        "row": 0,
+        "col": 2,
+        "char": " ",
+        "attrs": {
+          "bg_color": {
+            "named": 4
+          }
+        }
+      },
+      {
+        "row": 0,
+        "col": 3,
+        "char": "D"
+      }
+    ]
+  }
+}

